import { useState, useEffect } from "react";

export default function SubTaskModal({ subTask, onClose, onSave, loading }) {
  const [title,        setTitle]        = useState(subTask?.title        || "");
  const [totalMinutes, setTotalMinutes] = useState(String(subTask?.totalMinutes || ""));

  useEffect(() => {
    setTitle(subTask?.title || "");
    setTotalMinutes(String(subTask?.totalMinutes || ""));
  }, [subTask]);

  const canSubmit = !!title.trim();

  const handleSave = () => {
    onSave({
      title:        title.trim(),
      totalMinutes: parseInt(totalMinutes) || 0,
    });
  };

  return (
    <div
      className="modal-overlay"
      onClick={e => e.target === e.currentTarget && onClose()}
      style={{ zIndex: 300 }}
    >
      <div className="modal animate-scaleIn">
        <div className="modal-header">
          <div>
            <div className="modal-title">
              {subTask ? "✏️ Edit Sub-task" : "➕ Add Sub-task"}
            </div>
            <p className="text-sm text-gray" style={{ marginTop: 3 }}>
              {subTask ? "Update sub-task details." : "Add a sub-task with a title and optional work time."}
            </p>
          </div>
          <button className="modal-close" onClick={onClose}>✕</button>
        </div>

        <div className="modal-body">
          <div className="form-grid">
            {/* Title */}
            <div className="form-group full">
              <label className="form-label">Sub-task Title / Description</label>
              <textarea
                className="form-textarea"
                rows={3}
                value={title}
                onChange={e => setTitle(e.target.value)}
                placeholder="Describe this sub-task…"
                autoFocus
              />
            </div>

            {/* Total Work Time */}
            <div className="form-group full">
              <label className="form-label">
                Total Work Time
                <span style={{ marginLeft: 6, fontSize: 11, color: "#9ca3af", fontWeight: 400 }}>
                  (minutes — e.g. 90 = 1h 30m)
                </span>
              </label>
              <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
                <input
                  className="form-input"
                  type="number"
                  min="0"
                  value={totalMinutes}
                  onChange={e => setTotalMinutes(e.target.value)}
                  placeholder="e.g. 90"
                  style={{ maxWidth: 140 }}
                />
                {parseInt(totalMinutes) > 0 && (
                  <span style={{
                    fontSize: 13, fontWeight: 700, color: "#166534",
                    background: "#dcfce7", padding: "4px 10px", borderRadius: 8,
                  }}>
                    = {formatMinsDisplay(parseInt(totalMinutes))}
                  </span>
                )}
              </div>
            </div>
          </div>
        </div>

        <div className="modal-footer">
          <button className="btn btn-secondary" onClick={onClose}>Cancel</button>
          <button
            className="btn btn-primary"
            onClick={handleSave}
            disabled={loading || !canSubmit}
          >
            {loading ? "Saving…" : subTask ? "Update Sub-task" : "Add Sub-task"}
          </button>
        </div>
      </div>
    </div>
  );
}

// Show e.g. "1h 30m" or "45m" or "2h"
function formatMinsDisplay(mins) {
  if (!mins || mins <= 0) return "0m";
  const h = Math.floor(mins / 60);
  const m = mins % 60;
  if (h === 0) return `${m}m`;
  if (m === 0) return `${h}h`;
  return `${h}h ${m}m`;
}
